#!/usr/bin/env node
// Regenerates packages/shared/src/deployments.ts by inlining all per-network
// JSON manifests under packages/shared/src/deployments/. Mirrors the abis.ts
// codegen pattern: JSON files are canonical and editable; the TS file is an
// auto-generated import-friendly snapshot that gets compiled into dist/.

const fs = require('fs');
const path = require('path');

const deploymentsDir = path.join(__dirname, '..', 'src', 'deployments');
const outputPath = path.join(__dirname, '..', 'src', 'deployments.ts');

if (!fs.existsSync(deploymentsDir)) {
  console.error(`❌ deployments dir not found: ${deploymentsDir}`);
  process.exit(1);
}

const files = fs
  .readdirSync(deploymentsDir)
  .filter((f) => f.endsWith('.json'))
  .sort();

if (files.length === 0) {
  console.error(`❌ no deployment manifests found in ${deploymentsDir}`);
  process.exit(1);
}

const manifests = {};
for (const file of files) {
  const filePath = path.join(deploymentsDir, file);
  const content = JSON.parse(fs.readFileSync(filePath, 'utf8'));
  if (typeof content.chainId !== 'number') {
    console.warn(`⚠️  ${file} has no chainId, skipping`);
    continue;
  }
  manifests[content.chainId] = content;
}

const banner = `// Auto-generated by scripts/generateDeployments.js
// Do not edit by hand — edit the per-network JSON files under src/deployments/
// and run \`pnpm run build\` (or invoke this script directly).

`;

const interfaceBlock = `export interface ContractDeployment {
  address: string;
  deployBlock: number;
  txHash?: string;
  gasUsed?: string;
}

export interface DeploymentManifest {
  network: string;
  chainId: number;
  deployedAt: string | null;
  deployer: string | null;
  contracts: Record<string, ContractDeployment>;
}

`;

const entries = Object.values(manifests)
  .sort((a, b) => a.chainId - b.chainId)
  .map((m) => `  ${m.chainId}: ${JSON.stringify(m, null, 2).replace(/\n/g, '\n  ')}`)
  .join(',\n');

const body = `export const DEPLOYMENTS: Record<number, DeploymentManifest> = {
${entries},
};

export function getDeployment(chainId: number): DeploymentManifest {
  const d = DEPLOYMENTS[chainId];
  if (!d) throw new Error(\`No deployment manifest for chain \${chainId}\`);
  return d;
}
`;

fs.writeFileSync(outputPath, banner + interfaceBlock + body);

console.log(`✅ Generated ${outputPath} from ${files.length} manifest(s):`);
for (const f of files) console.log(`   - ${f}`);
